function compareSemver(a, b) {
  const pa = a.replace(/^v/, "").split(".").map(Number);
  const pb = b.replace(/^v/, "").split(".").map(Number);
  for (let i = 0;i < 3; i++) {
    const diff = (pa[i] ?? 0) - (pb[i] ?? 0);
    if (diff !== 0) {
      return diff;
    }
  }
  return 0;
}
async function fetchLatestVersion() {
  try {
    const resp = await fetch(`https://api.github.com/repos/${REPO}/releases/latest`, {
      headers: { Accept: "application/vnd.github+json", "User-Agent": "agent-slack-updater" },
      signal: AbortSignal.timeout(5000)
    });
    if (!resp.ok) {
      return null;
    }
    const data = await resp.json();
    return data.tag_name?.replace(/^v/, "") ?? null;
  } catch {
    return null;
  }
}
async function checkForUpdate(force = false) {
  const current = getPackageVersion();
  if (!force) {
    const cached2 = await readJsonFile(getCachePath());
    if (cached2 && Date.now() - cached2.checked_at < CHECK_INTERVAL_MS) {
      return {
        current,
        latest: cached2.latest_version,
        update_available: compareSemver(cached2.latest_version, current) > 0
      };
    }
  }
  const latest = await fetchLatestVersion();
  if (!latest) {
    return null;
  }
  try {
    await writeJsonFile(getCachePath(), {
      latest_version: latest,
      checked_at: Date.now()
    });
  } catch {}
  return {
    current,
    latest,
    update_available: compareSemver(latest, current) > 0
  };
}
function detectInstallMethod() {
  if (process.versions.bun && basename3(process.execPath) === "bun") {
    return "bun";
  }
  const execName = basename3(process.execPath);
  if (["node", "nodejs", "node.exe"].includes(execName) || process.env.npm_execpath) {
    return "npm";
  }
  return "binary";
}
function getUpdateCommand(method) {
  const m = method ?? detectInstallMethod();
  switch (m) {
    case "npm":
      return "npm install -g agent-slack@latest";
    case "bun":
      return "bun install -g agent-slack@latest";
    case "binary":
      return "agent-slack update";
  }
}
function performPackageManagerUpdate(method) {
  const cmd = getUpdateCommand(method);
  try {
    execSync2(cmd, { stdio: ["inherit", "pipe", "inherit"] });
    return { success: true, message: `Updated agent-slack via: ${cmd}` };
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    return { success: false, message: `Failed to run "${cmd}": ${msg}` };
  }
}
function detectPlatformAsset() {
  const platform7 = process.platform === "win32" ? "windows" : process.platform;
  const archMap = { x64: "x64", arm64: "arm64" };
  const arch = archMap[process.arch] ?? process.arch;
  const ext = platform7 === "windows" ? ".exe" : "";
  return `agent-slack-${platform7}-${arch}${ext}`;
}
async function sha256(filePath) {
  const data = await readFile7(filePath);
  return createHash2("sha256").update(data).digest("hex");
}
async function performUpdate(latest) {
  const asset = detectPlatformAsset();
  const tag = `v${latest}`;
  const baseUrl = `https://github.com/${REPO}/releases/download/${tag}`;
  const tmp = join15(tmpdir5(), `agent-slack-update-${Date.now()}`);
  await mkdir5(tmp, { recursive: true });
  const binTmp = join15(tmp, asset);
  const sumsTmp = join15(tmp, "checksums-sha256.txt");
  try {
    const [binResp, sumsResp] = await Promise.all([
      fetch(`${baseUrl}/${asset}`, { signal: AbortSignal.timeout(120000) }),
      fetch(`${baseUrl}/checksums-sha256.txt`, { signal: AbortSignal.timeout(30000) })
    ]);
    if (!binResp.ok) {
      return { success: false, message: `Failed to download ${asset}: HTTP ${binResp.status}` };
    }
    if (!sumsResp.ok) {
      return { success: false, message: `Failed to download checksums: HTTP ${sumsResp.status}` };
    }
    await writeFile4(binTmp, Buffer.from(await binResp.arrayBuffer()));
    const sumsText = await sumsResp.text();
    await writeFile4(sumsTmp, sumsText);
    const expected = sumsText.split(`
`).map((line) => line.trim().split(/\s+/)).find((parts) => parts[1] === asset)?.[0];
    if (!expected) {
      return { success: false, message: `Checksum not found for ${asset} in release checksums` };
    }
    const actual = await sha256(binTmp);
    if (actual !== expected) {
      return { success: false, message: `Checksum mismatch: expected ${expected}, got ${actual}` };
    }
    if (process.platform === "darwin") {
      try {
        execSync2(`codesign --remove-signature ${JSON.stringify(binTmp)}`, {
          stdio: "ignore"
        });
        execSync2(`codesign --sign - ${JSON.stringify(binTmp)}`, {
          stdio: "ignore"
        });
      } catch {}
    }
    const currentBin = process.execPath;
    const backupPath = `${currentBin}.bak`;
    await rename(currentBin, backupPath);
    try {
      await copyFile2(binTmp, currentBin);
      await chmod(currentBin, 493);
      await rm3(backupPath, { force: true });
    } catch (err) {
      try {
        await rename(backupPath, currentBin);
      } catch {}
      throw err;
    }
    return { success: true, message: `Updated agent-slack to ${latest}` };
  } finally {
    await rm3(tmp, { recursive: true, force: true }).catch(() => {});
  }
}
async function backgroundUpdateCheck() {
  if (process.env.AGENT_SLACK_NO_UPDATE_CHECK === "1") {
    return;
  }
  try {
    const result = await checkForUpdate();
    if (result?.update_available) {
      const cmd = getUpdateCommand();
      process.stderr.write(`
Update available: ${result.current} \u2192 ${result.latest}. Run "${cmd}" to upgrade.
`);
    }
  } catch {}
}

// src/cli/update-command.ts
function registerUpdateCommand(input) {
  input.program.command("update").description("Update agent-slack to the latest version").option("--check", "Only check for updates (don't install)").action(async (...args) => {
    const [options] = args;
    const method = detectInstallMethod();
    try {
      const result = await checkForUpdate(true);
      if (!result) {
        console.error("Could not check for updates. Check your network connection.");
        process.exitCode = 1;
        return;
      }
      if (!result.update_available) {
        console.log(JSON.stringify(pruneEmpty({ ...result, install_method: method, status: "up_to_date" }), null, 2));
        return;
      }
      if (options.check) {
        console.log(JSON.stringify(pruneEmpty({
          ...result,
          install_method: method,
          update_command: getUpdateCommand(method),
          status: "update_available"
        }), null, 2));
        return;
      }
      process.stderr.write(`Updating agent-slack ${result.current} \u2192 ${result.latest}...
`);
      let outcome;
      if (method === "npm" || method === "bun") {
        process.stderr.write(`Detected install method: ${method}
`);
        outcome = performPackageManagerUpdate(method);
      } else {
        outcome = await performUpdate(result.latest);
      }
      if (!outcome.success) {
        console.error(outcome.message);
        process.exitCode = 1;
        return;
      }
      console.log(JSON.stringify(pruneEmpty({
        status: "updated",
        install_method: method,
        previous_version: result.current,
        new_version: result.latest,
        message: outcome.message
      }), null, 2));
    } catch (err) {
      console.error(err instanceof Error ? err.message : String(err));
      process.exitCode = 1;
    }
  });
}

